# OEIS sequence: A036505

from sympy import factorint
from sympy.ntheory.factor_ import digits
def A036505(n):
    m = (n+1)**n
    for p, e in factorint(n+1).items():
        m //= p**min(e*n,(n-sum(digits(n,p)[1:]))//(p-1))
    return m # _Chai Wah Wu_, May 03 2026

